# This system facilitates collaborative financial planning among multiple users.

class FinancialCollaborator:
    def __init__(self):
        self.goals = {}
        self.contributions = {}

    def add_goal(self, goal_id, description, target_amount):
        """Add a new financial goal."""
        if goal_id in self.goals:
            raise ValueError(f"Goal with ID {goal_id} already exists.")
        self.goals[goal_id] = {
            'description': description,
            'target_amount': target_amount,
            'current_amount': 0
        }
        self.contributions[goal_id] = {}

    def add_contribution(self, goal_id, user_id, amount):
        """Add a contribution to a financial goal."""
        if goal_id not in self.goals:
            raise ValueError(f"Goal with ID {goal_id} does not exist.")
        if amount <= 0:
            raise ValueError("Contribution amount must be positive.")
        if user_id not in self.contributions[goal_id]:
            self.contributions[goal_id][user_id] = 0
        self.contributions[goal_id][user_id] += amount
        self.goals[goal_id]['current_amount'] += amount

    def get_goal_status(self, goal_id):
        """Get the status of a financial goal."""
        if goal_id not in self.goals:
            raise ValueError(f"Goal with ID {goal_id} does not exist.")
        goal = self.goals[goal_id]
        return {
            'description': goal['description'],
            'target_amount': goal['target_amount'],
            'current_amount': goal['current_amount'],
            'progress': goal['current_amount'] / goal['target_amount'] * 100
        }

    def get_contributions(self, goal_id):
        """Get contributions for a financial goal."""
        if goal_id not in self.goals:
            raise ValueError(f"Goal with ID {goal_id} does not exist.")
        return self.contributions[goal_id]

# Example usage
